@namespace Lumeo

<details class="@RootClass" open="@DefaultOpen" @attributes="AdditionalAttributes">
    <summary class="@SummaryClass">
        <span class="inline-flex h-3.5 w-3.5 shrink-0 items-center justify-center text-muted-foreground transition-transform duration-150 [details[open]_&]:rotate-90">
            <Icon Name="ChevronRight" Size="Lumeo.Size.Sm" />
        </span>
        @* aria-live="polite" on the summary text wrapper so when IsStreaming
           flips and ResolvedSummary changes ("Thinking…" → "Reasoned for 1.2s"),
           assistive tech announces the transition. aria-atomic re-reads the
           whole label rather than the diff. *@
        <span class="italic text-muted-foreground" aria-live="polite" aria-atomic="true">@ResolvedSummary</span>
        @if (IsStreaming)
        {
            <span class="inline-flex items-center" aria-hidden="true">
                <span class="h-1 w-1 rounded-[calc(var(--radius)*2)] bg-muted-foreground animate-pulse"></span>
            </span>
        }
    </summary>

    <div class="@BodyClass">
        @if (Markdown)
        {
            <div class="prose prose-sm max-w-none break-words">@RenderedMarkdown</div>
        }
        else
        {
            <p class="m-0 whitespace-pre-wrap break-words">@Text</p>
        }
    </div>
</details>

@code {
    [Parameter] public string? Text { get; set; }
    [Parameter] public bool IsStreaming { get; set; }
    [Parameter] public string? Summary { get; set; }
    [Parameter] public long? DurationMs { get; set; }
    [Parameter] public bool DefaultOpen { get; set; }
    [Parameter] public Lumeo.Size Size { get; set; } = Lumeo.Size.Md;
    [Parameter] public ReasoningVariant Variant { get; set; } = ReasoningVariant.Default;

    /// <summary>
    /// Renders <see cref="Text"/> as markdown instead of plain text — reasoning
    /// traces from models are usually markdown (lists, bold, code). Uses
    /// <see cref="MarkdownRenderer"/> when supplied, otherwise the built-in
    /// dependency-free CommonMark subset. Pairs naturally with
    /// <see cref="ReasoningVariant.Detailed"/>. (#305)
    /// </summary>
    [Parameter] public bool Markdown { get; set; }

    /// <summary>
    /// Optional render hook converting the raw markdown <see cref="Text"/> into a
    /// <see cref="MarkupString"/> (plug in Markdig etc.). The delegate must return
    /// SAFE HTML — sanitise untrusted input. Ignored unless <see cref="Markdown"/>
    /// is <c>true</c>.
    /// </summary>
    [Parameter] public Func<string, MarkupString>? MarkdownRenderer { get; set; }

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string RootClass => Cx.Merge("w-full min-w-0 max-w-full overflow-hidden", VariantRootClass, Class);

    private string VariantRootClass => Variant switch
    {
        ReasoningVariant.Compact => "opacity-80",
        ReasoningVariant.Detailed => "space-y-1",
        _ => ""
    };

    private string SummaryClass => Size switch
    {
        Lumeo.Size.Sm =>
            "flex cursor-pointer list-none items-center gap-1.5 text-[11px] text-muted-foreground hover:text-foreground transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1 rounded select-none [&::-webkit-details-marker]:hidden",
        Lumeo.Size.Lg =>
            "flex cursor-pointer list-none items-center gap-2.5 text-sm text-muted-foreground hover:text-foreground transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1 rounded select-none [&::-webkit-details-marker]:hidden",
        _ =>
            "flex cursor-pointer list-none items-center gap-2 text-xs text-muted-foreground hover:text-foreground transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1 rounded select-none [&::-webkit-details-marker]:hidden"
    };

    private string BodyClass
    {
        get
        {
            // ms-1 adds breathing room between the rotated chevron column and the rule,
            // ps-4 puts enough gap between the rule and the reasoning text.
            var sizeClass = Size switch
            {
                Lumeo.Size.Sm => "mt-1.5 ms-1 border-s-2 border-border/40 ps-3 py-0.5 text-[11px] leading-relaxed text-muted-foreground",
                Lumeo.Size.Lg => "mt-2.5 ms-1 border-s-2 border-border/40 ps-5 py-1.5 text-sm leading-relaxed text-muted-foreground",
                _ => "mt-2 ms-1 border-s-2 border-border/40 ps-4 py-1 text-xs leading-relaxed text-muted-foreground"
            };
            // Detailed variant shows full untruncated text; compact variant limits visible lines
            var variantExtra = Variant switch
            {
                ReasoningVariant.Compact => " line-clamp-3",
                ReasoningVariant.Detailed => "",
                _ => ""
            };
            var baseClass = $"{sizeClass}{variantExtra}";
            return IsStreaming ? $"{baseClass} animate-pulse" : baseClass;
        }
    }

    private string ResolvedSummary
    {
        get
        {
            if (!string.IsNullOrEmpty(Summary)) return Summary!;
            if (DurationMs is long ms) return $"Reasoned for {ms / 1000.0:0.#}s";
            return IsStreaming ? "Thinking…" : "Reasoning";
        }
    }

    // Mirrors StreamingText: HTML-escape-first allow-list renderer by default,
    // or a consumer-supplied renderer. LumeoMarkdown output is XSS-safe. (#305)
    private MarkupString RenderedMarkdown
    {
        get
        {
            var text = Text ?? string.Empty;
            if (text.Length == 0) return default;
            return MarkdownRenderer is not null
                ? MarkdownRenderer(text)
                : (MarkupString)Lumeo.Internal.LumeoMarkdown.ToHtml(text);
        }
    }

    /// <summary>
    /// Default = standard expand/collapse display.
    /// Compact = summary label + collapsed body limited to 3 lines.
    /// Detailed = always shows full body text with extra padding.
    /// </summary>
    public enum ReasoningVariant { Default, Compact, Detailed }
}
